mapper.select:
SELECT s.id, s.user_id AS userId, s.student_number AS studentNumber, s.school, s.college, s.major, s.enrollment_year AS enrollmentYear, s.expected_graduation AS expectedGraduation, s.gpa, s.total_credits AS totalCredits, s.created_time AS createdTime, s.updated_time AS updatedTime, u.real_name AS realName, u.nickname, u.avatar, u.email, u.phone FROM students s LEFT JOIN users u ON s.user_id = u.id
AND s.student_number = #{q.studentNumber}
AND s.college LIKE CONCAT('%', #{q.college}, '%')
AND s.major LIKE CONCAT('%', #{q.major}, '%')
AND s.enrollment_year = #{q.enrollmentYear}
ORDER BY s.created_time DESC
